import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch2: ScenarioQuestion[] = [
  q("sq-bg2-1",ip,"behavioral","You assisted a patient with mobility issues during clinical.","How did you help a patient with limited mobility?","I noticed a patient struggling to reach their water pitcher due to post-stroke weakness. I repositioned all essential items within their functional reach, obtained an adaptive cup with a built-in straw, and coordinated with OT for assistive device evaluation. The patient's independence with hydration improved immediately, and the OT team incorporated my observations into their treatment plan.","Practical problem-solving for functional limitations.","beginner"),
  q("sq-bg2-2",ip,"behavioral","You witnessed an ethical violation during clinical.","How did you handle witnessing an ethical concern?","I observed a staff member photographing a patient's wound on a personal phone without consent. I reported the concern to my clinical instructor immediately, who addressed it with the unit manager. The incident reinforced for me that patient privacy must be protected absolutely, and that reporting concerns through proper channels is a professional obligation.","Reporting ethical violations through proper channels.","intermediate"),
  q("sq-bg2-3",ip,"behavioral","You are asked about managing competing priorities in nursing.","How do you juggle multiple nursing responsibilities?","I use a combination of clinical prioritization frameworks and organizational tools. I assess all patients at the start of the shift, identify the most acute needs, cluster care activities, delegate appropriately, and maintain a running to-do list that I reprioritize throughout the shift. I communicate with my team about my workload so we can support each other effectively.","Systematic approach to workload management.","beginner"),
  q("sq-bg2-4",ip,"clinical_judgment","A patient has a sodium level of 118 mEq/L.","What does severe hyponatremia require?","A sodium of 118 is severe hyponatremia and can cause cerebral edema, seizures, and death. I would implement seizure precautions, restrict fluids per protocol, notify the provider immediately, and anticipate hypertonic saline administration in a monitored setting. Correction must be gradual—no more than 8-12 mEq/L in 24 hours to prevent osmotic demyelination syndrome.","Severe hyponatremia as a neurological emergency with controlled correction.","advanced"),
  q("sq-bg2-5",ip,"clinical_judgment","A patient with ESRD misses their scheduled dialysis session.","What are the risks of missed dialysis?","Missed dialysis leads to fluid overload, electrolyte imbalances (especially hyperkalemia), uremia, and metabolic acidosis. I would assess for fluid overload signs (edema, crackles, jugular vein distention), check potassium and BUN levels, monitor for cardiac arrhythmias, restrict fluids and potassium intake, and arrange for urgent dialysis. Missed sessions significantly increase morbidity and mortality risk.","Consequences of missed dialysis and urgent management.","intermediate"),
  q("sq-bg2-6",ip,"clinical_judgment","A patient receiving chemotherapy develops mouth sores that prevent eating.","How would you manage chemotherapy-induced mucositis?","I would assess the severity of mucositis using a grading scale, provide oral care with soft toothbrush and non-alcohol mouthwash, administer prescribed pain medications before meals, offer soft bland foods at room temperature, consult nutrition services about supplements, and notify the provider about the severity. Adequate oral care and nutrition support are essential during treatment.","Comprehensive mucositis management supporting nutrition and comfort.","intermediate"),
  q("sq-bg2-7",ip,"clinical_judgment","A patient with a history of seizures suddenly develops rhythmic jerking movements.","How would you manage an active seizure?","I would time the seizure, ensure patient safety by lowering the bed, removing nearby objects, and placing padding around the head. I would not put anything in the patient's mouth or restrain them. I would turn them on their side to prevent aspiration, apply oxygen, call for help, and have suction ready. I would administer anticonvulsants per protocol and document the seizure characteristics for the neurologist.","Active seizure management with safety priority.","intermediate"),
  q("sq-bg2-8",ip,"clinical_judgment","A patient on continuous cardiac monitoring develops torsades de pointes.","What is torsades and how would you respond?","Torsades de pointes is a polymorphic ventricular tachycardia associated with prolonged QT interval. It can degenerate into ventricular fibrillation. I would call a code, begin CPR if the patient is pulseless, prepare for defibrillation, and anticipate IV magnesium sulfate as the first-line treatment. I would review medications that prolong QT interval and check electrolyte levels.","Torsades recognition with magnesium-first treatment approach.","advanced"),
  q("sq-bg2-9",ip,"clinical_judgment","A patient with chronic liver disease develops coffee-ground emesis.","What does coffee-ground emesis indicate?","Coffee-ground emesis indicates upper GI bleeding where blood has been partially digested by stomach acid. In a liver disease patient, this is likely from esophageal varices or gastric erosions. I would assess hemodynamic stability, establish large-bore IV access, send blood for type and crossmatch and CBC, keep the patient NPO, insert an NG tube if ordered, and notify the gastroenterologist for emergent endoscopy.","Upper GI bleeding recognition in liver disease patients.","advanced"),
  q("sq-bg2-10",ip,"clinical_judgment","A patient develops subcutaneous emphysema around their neck after a central line insertion.","What does subcutaneous emphysema suggest after central line placement?","Subcutaneous emphysema—air under the skin creating a crackling sensation on palpation—after central line insertion suggests pneumothorax. Air has escaped from the pleural space or lung into the subcutaneous tissue. I would obtain a stat chest X-ray, assess respiratory status, apply oxygen, and notify the provider immediately. The patient may need a chest tube if the pneumothorax is significant.","Post-procedure pneumothorax recognition.","advanced"),
  q("sq-bg2-11",ip,"scenario_responses","A patient refuses to take their medications because they believe they are being poisoned.","How would you handle medication refusal based on paranoia?","I would not force medications. I would calmly and patiently explain each medication's purpose. I would offer to open the medication in front of them or let them see the original packaging. I would involve the psychiatry team if paranoia is new. I would document the refusal and the patient's stated reason. If the patient lacks capacity and the medications are critical, I would follow the involuntary treatment protocol.","De-escalation and alternative administration approaches for paranoid patients.","advanced"),
  q("sq-bg2-12",ip,"scenario_responses","A patient wants to leave the hospital to attend a family wedding.","How would you handle a patient wanting temporary hospital leave?","I would explore the clinical feasibility with the care team. If the patient is stable enough, some facilities allow supervised leave with provider approval. I would discuss risks, ensure medications are covered, provide emergency instructions, and document the plan. If leave is not medically advisable, I would help explore alternatives like video calling during the ceremony.","Creative solutions for patient quality of life within safety constraints.","intermediate"),
  q("sq-bg2-13",ws,"prioritization","You have a patient whose blood sugar is 45 and another patient reporting 10/10 pain.","Which patient do you see first?","Hypoglycemia at 45 mg/dL is a medical emergency that can lead to seizures and brain damage if untreated. I would treat the hypoglycemia first with 15g fast-acting glucose and reassess in 15 minutes. I would then immediately address the patient in pain. While pain is important, it is not immediately life-threatening. I would communicate to the pain patient that I am coming shortly.","Life-threatening metabolic emergencies before pain management.","beginner"),
  q("sq-bg2-14",ws,"prioritization","At change of shift, you discover a patient's morning medications were not given.","How would you handle discovering missed morning medications?","I would assess which medications were missed and their time-sensitivity. I would administer critical medications immediately if still within the safe administration window. For time-sensitive medications like antibiotics, I would adjust the schedule. I would document the missed doses and late administrations. I would report the omission through the incident reporting system and notify the provider.","Time-critical medication recovery with incident reporting.","intermediate"),
  q("sq-bg2-15",ws,"delegation","You need to delegate ambulation to a new CNA for a patient with a recent knee replacement.","How would you safely delegate post-surgical ambulation?","I would provide specific instructions: 'Mrs. Thompson in room 312 needs to ambulate to the door and back with her walker. She is weight-bearing as tolerated on her right leg. Please watch for dizziness, pain, or instability. If she reports increased pain above 6/10 or shows signs of unsteadiness, stop and assist her back to bed. Report back to me when done.' Clear parameters ensure safe delegation.","Specific, measurable delegation parameters for post-surgical mobility.","beginner"),
  q("sq-bg2-16",ws,"delegation","You delegate a bed bath to a CNA but the patient has a central line and chest tubes.","How would you delegate care around complex lines and devices?","I would specify which areas the CNA can and cannot clean, remind them not to manipulate any lines or tubes, and instruct them to call me if anything becomes disconnected or if they notice any changes in drainage. I would check all lines and connections after the bath is complete. For patients with complex devices, close coordination between RN and CNA is essential.","Device-aware delegation with specific restriction communication.","intermediate"),
  q("sq-bg2-17",ws,"patient_safety","A patient on seizure precautions has the bed rails raised on all sides.","Is this seizure precaution correct?","Having all four bed rails raised is actually considered a restraint in many facilities and can increase injury risk if a patient climbs over them. Proper seizure precautions include padded side rails with the bed in the lowest position, suction and oxygen at bedside, and the patient on their side. I would adjust the rails per policy and ensure proper seizure equipment is available.","Correcting well-intentioned but potentially harmful safety measures.","intermediate"),
  q("sq-bg2-18",ws,"patient_safety","You notice that medication labels are faded and hard to read on some IV bags.","How would you handle medication labeling issues?","I would replace any bag with an illegible label immediately—never administer a medication you cannot clearly identify. I would contact pharmacy for properly labeled replacements. I would report the labeling issue through the safety reporting system. I would check all hanging IV medications for label legibility. Unclear labels are a medication error waiting to happen.","Medication identification verification and replacement for safety.","beginner"),
  q("sq-bg2-19",ws,"medication_error","You accidentally give a medication 2 hours early.","How would you handle giving a medication early?","I would assess the patient for any adverse effects related to the early administration. I would check whether the early dose creates a dosing interval concern with the next scheduled dose. I would notify the provider, adjust the timing of the next dose if needed, document the error and the patient's response, and file an incident report. I would analyze why the timing error occurred.","Timing error management with dose interval assessment.","beginner"),
  q("sq-bg2-20",ws,"handoff_communication","You need to give handoff for a patient with multiple drip rate changes during your shift.","How would you communicate complex drip management during handoff?","I would organize drip information clearly: current medication, current rate, recent rate changes with rationale, titration parameters, most recent assessment findings that guided changes, and upcoming assessment schedule. I would provide the trend: 'The vasopressin was decreased from 0.04 to 0.02 units/min over the last 4 hours as MAP improved from 58 to 72.' Trends tell a better story than just current rates.","Trend-based communication for complex drip management.","advanced"),
  q("sq-bg2-21",ws,"difficult_coworkers","A colleague consistently questions your clinical decisions in front of others.","How would you address persistent public questioning?","I would address it privately: 'I have noticed you frequently question my clinical decisions in front of the team. I welcome constructive feedback, but I would prefer it be shared privately so we can have a productive discussion. If you have concerns about patient safety, I am always open to hearing them.' If public questioning continued, I would involve the manager and document specific incidents.","Private address of public questioning patterns.","intermediate"),
  q("sq-bg2-22",ws,"difficult_coworkers","A traveling nurse on your unit refuses to follow unit-specific protocols.","How would you address a travel nurse not following unit protocols?","I would approach them respectfully: 'I know every facility does things a bit differently. Our unit protocol for [specific task] is [method]. Can I show you how we do it here?' If they continued to resist, I would escalate to the charge nurse, as protocol adherence is a patient safety issue regardless of employment status.","Respectful protocol education with safety-based escalation.","intermediate"),
  q("sq-bg2-23",ws,"interdisciplinary_communication","The pharmacist recommends a medication change but the physician disagrees.","How would you navigate pharmacist-physician disagreement?","I would not take sides but would ensure the concern is communicated: 'The pharmacist has recommended [alternative] because of [clinical reason]. The physician prefers to continue the current medication. I want to make sure both perspectives are documented in the patient's record.' I would encourage direct pharmacist-physician communication and document my advocacy efforts.","Facilitating direct communication between disagreeing providers.","intermediate"),
  q("sq-bg2-24",ct,"first_shift","You make a great clinical catch and your preceptor praises you.","How would you build on a positive clinical experience?","I would reflect on what led to the good catch—what assessment skills, critical thinking, and knowledge contributed. I would write it down in my clinical confidence journal. I would use the positive experience to build momentum for the next shift. I would share the learning with my cohort. Positive experiences deserve as much reflection as mistakes—they reinforce good habits.","Building confidence through positive reflection.","beginner"),
  q("sq-bg2-25",ct,"first_shift","A patient tells you that you are the best nurse they have ever had.","How would you respond to a patient's high praise?","I would thank them genuinely while remaining humble: 'That means a lot to me. I just want to make sure you feel cared for while you are here.' I would not let praise lead to complacency—I would continue providing the same level of care. I would remember these moments during difficult days when self-doubt creeps in.","Gracious acceptance without complacency.","beginner"),
  q("sq-bg2-26",ct,"new_nurse_anxiety","You are worried about making a fatal error.","How would you manage the fear of causing patient harm?","I would acknowledge that this fear is common and shows that I take my responsibility seriously. I would use systems designed to prevent harm: medication scanning, checklists, double-checks, and asking for help. I would remind myself that nursing education and licensure ensure baseline competency. If anxiety is paralyzing, I would seek professional support. A healthy fear of making errors is protective; a paralyzing one needs attention.","Healthy error-fear management through safety systems.","beginner"),
  q("sq-bg2-27",ct,"new_nurse_anxiety","You compare yourself unfavorably to other new graduates in your cohort.","How would you handle peer comparison anxiety?","I would remember that everyone's clinical journey is different. My colleague may be stronger in one area while I excel in another. I would focus on my own growth trajectory rather than ranking against peers. I would seek collaboration rather than competition—sharing knowledge and supporting each other makes everyone stronger. Nursing is not a competition; it is a collaborative profession.","Shifting from competitive to collaborative mindset.","beginner"),
  q("sq-bg2-28",ct,"time_management","You are struggling to balance physical care with emotional support.","How would you integrate emotional care into physical tasks?","I would combine them: use assessment time to ask about emotional wellbeing, provide education during medication administration, and have meaningful conversations during positioning or wound care. Every physical interaction is an opportunity for therapeutic communication. I would also schedule specific times for longer emotional conversations when the patient needs dedicated attention.","Integrating emotional care into routine physical tasks.","beginner"),
  q("sq-bg2-29",ct,"documentation_challenges","You need to document an incident report for a near-miss.","How would you complete a near-miss incident report?","I would document factually: what almost happened, how it was caught, what prevented the error from reaching the patient, and what systemic factors contributed. I would not assign blame—incident reports are for system improvement, not punishment. I would be specific and objective. Near-miss reporting is actually more valuable than actual-error reporting because it identifies system vulnerabilities before harm occurs.","Near-miss reporting as proactive safety improvement.","beginner"),
  q("sq-bg2-30",ct,"critical_thinking_drills","A patient's white blood cell count is 22,000.","What does leukocytosis suggest?","A WBC of 22,000 (normal 4,500-11,000) indicates leukocytosis, suggesting infection, inflammation, stress response, or leukemia. I would assess for signs of infection (fever, localized symptoms), review recent procedures or surgeries, check other inflammatory markers, and correlate with the patient's clinical picture. I would notify the provider and anticipate blood cultures, imaging, or other workup based on the suspected cause.","Leukocytosis interpretation with differential diagnosis consideration.","intermediate"),
  q("sq-bg2-31",ct,"critical_thinking_drills","A patient has a positive troponin but normal ECG.","What does this mean clinically?","A positive troponin with a normal ECG can indicate a non-ST-elevation myocardial infarction (NSTEMI), which does not show the classic ST changes on ECG but still represents cardiac injury. It could also indicate myocarditis, pulmonary embolism, sepsis-related cardiac stress, or chronic kidney disease. Serial troponins and clinical context are essential. I would notify the provider, continue cardiac monitoring, and anticipate possible cardiac catheterization.","Understanding that normal ECG does not rule out cardiac injury.","intermediate"),
  q("sq-bg2-32",pd,"professional_boundaries","A patient gives you their social media information and wants to keep in touch after discharge.","How would you maintain boundaries after patient discharge?","I would explain that professional boundaries prevent me from maintaining personal relationships with patients: 'I have enjoyed caring for you and wish you the best in your recovery. However, maintaining professional boundaries means I cannot connect on social media. If you need follow-up care, your healthcare team is the best resource.' I would not accept social media connections from patients.","Consistent post-discharge boundary maintenance.","beginner"),
  q("sq-bg2-33",pd,"ethical_dilemmas","A dying patient tells you they want to die at home but their family insists on hospital care.","How would you navigate the patient's wishes versus family preferences?","I would advocate for the patient's wishes if they have decision-making capacity. I would facilitate a family meeting with the patient present to discuss their wishes. I would involve palliative care and social work. I would explain to the family that the patient's autonomy must be respected. I would help arrange home hospice services if the patient chooses to go home.","Patient autonomy advocacy with family support.","advanced"),
  q("sq-bg2-34",pd,"ethical_dilemmas","You discover that a colleague has been diverting controlled substances.","How would you handle suspected drug diversion by a colleague?","I would not confront the colleague directly. I would report my suspicions immediately to my nurse manager and the charge nurse, providing specific observations: discrepancies in counts, patients reporting inadequate pain relief, changes in behavior. I would document my observations objectively. Drug diversion is a patient safety and legal issue that requires immediate management and investigation.","Immediate reporting of drug diversion through proper channels.","advanced"),
  q("sq-bg2-35",pd,"workplace_bullying","A group of nurses give you the silent treatment after you reported a safety concern.","How would you handle retaliation for safety reporting?","I would document the retaliatory behavior with specific dates and incidents. I would continue to perform my duties professionally. I would report the retaliation to HR and my manager—retaliation for safety reporting is prohibited and often illegal. I would seek support from the employee assistance program. I would not withdraw my safety report under social pressure.","Anti-retaliation documentation and reporting.","advanced"),
  q("sq-bg2-36",pd,"advocacy","A patient needs a service animal but the hospital has a strict no-pet policy.","How would you advocate for service animal accommodation?","I would review ADA requirements, which mandate reasonable accommodation for service animals. I would educate the appropriate staff about the distinction between service animals, emotional support animals, and pets. I would work with the patient to ensure their service animal's needs are met while maintaining infection control. I would advocate for a policy review if the current policy does not comply with ADA.","ADA compliance advocacy for service animals.","intermediate"),
  q("sq-bg2-37",pd,"patient_communication","A patient with hearing loss is frustrated because no one has been communicating effectively with them.","How would you improve communication for a hearing-impaired patient?","I would face the patient directly, speak clearly at a normal volume, reduce background noise, use visual aids and written materials, and ensure their hearing aid is functional if they have one. I would place a communication alert in the chart and on the door. I would arrange for assistive devices if available. I would educate all team members about the patient's communication needs.","Comprehensive hearing-impaired communication approach.","beginner"),
  q("sq-bg2-38",pd,"patient_communication","A patient with intellectual disability needs pre-operative teaching.","How would you adapt teaching for a patient with intellectual disability?","I would use simple, concrete language and short sentences. I would break instructions into small steps. I would use pictures, models, and demonstrations. I would involve their caregiver in the teaching. I would allow extra time and repeat information without frustration. I would verify understanding through demonstration rather than verbal teach-back. I would ensure the consent process appropriately involves the patient and their guardian.","Adaptive communication for intellectual disability.","intermediate"),
  q("sq-bg2-39",cn,"job_offer_negotiation","You are offered a position but want a later start date for personal reasons.","How would you negotiate a delayed start date?","I would express enthusiasm while being honest: 'I am very excited about this position. I have a personal commitment through [date]. Would it be possible to start on [proposed date] instead? I want to arrive ready to give my full focus to orientation and patient care.' Most employers accommodate reasonable start date requests when asked professionally.","Honest negotiation for practical scheduling needs.","beginner"),
  q("sq-bg2-40",cn,"probation_period","You receive feedback that you need to speak up more during team meetings.","How would you develop assertiveness in team settings?","I would start by preparing one comment or question before each meeting. I would practice speaking up in low-stakes situations first. I would use phrases like 'I noticed that...' or 'I have a question about...' to ease into participation. I would set a goal to contribute at least once per meeting. Over time, speaking up becomes more natural as I build confidence in my voice being valued.","Graduated assertiveness development.","beginner"),
  q("sq-bg2-41",cn,"career_advancement","You are interested in pediatric nursing but work on an adult unit.","How would you transition to pediatric nursing?","I would gain PALS certification, attend pediatric nursing conferences, and network with pediatric nurses. I would request any pediatric-related experiences on my current unit. I would apply for internal transfers when positions open. I would prepare for the differences: developmental assessments, family-centered care, medication dosing by weight, and communication with children of different ages.","Strategic preparation for specialty transition.","beginner"),
  q("sq-bg2-42",ip,"star_examples","Tell me about a time you improved efficiency on your unit.","Describe a workflow improvement you initiated.","I noticed that medication administration was frequently delayed because nurses had to walk to the far end of the unit for supplies. I proposed relocating commonly used supplies to a more central location and creating standardized supply carts for each room. After implementation, our medication timeliness improved by 15%, and nurse satisfaction scores on workflow efficiency increased.","Data-driven workflow improvement with measurable results.","intermediate"),
  q("sq-bg2-43",ip,"star_examples","Tell me about a time you managed a conflict between team members.","Describe your conflict resolution skills in practice.","Two CNAs had an ongoing scheduling dispute that was creating tension during shifts. I brought them together during a quiet moment, acknowledged both perspectives, and helped them establish a fair rotation schedule that they both agreed to. I followed up weekly for a month to ensure the agreement was holding. The unit atmosphere improved noticeably.","Active mediation with follow-up accountability.","intermediate"),
  q("sq-bg2-44",ip,"common_nursing_interview","The interviewer asks: 'Where do you see yourself in 5 years?'","How would you answer a career trajectory question?","In five years, I see myself as an experienced, confident nurse who has earned specialty certification and is mentoring new graduates. I want to be the kind of resource nurse that new staff seek out for guidance. I am interested in eventually pursuing a charge nurse role and possibly beginning a graduate program that aligns with my clinical interests.","Specific, realistic career vision with growth milestones.","beginner"),
  q("sq-bg2-45",ip,"common_nursing_interview","The interviewer asks: 'Why should we hire you over other candidates?'","How do you differentiate yourself from other candidates?","While I cannot speak to other candidates' qualifications, I can tell you what I bring: strong clinical skills validated by my preceptors, genuine passion for patient-centered care, a track record of initiative in quality improvement, and the resilience and work ethic I developed through working as a CNA while completing my nursing degree. I am committed to this unit specifically because of its reputation for excellence.","Specific personal strengths without disparaging competitors.","beginner"),
  q("sq-bg2-46",ip,"difficult_interviewer","The interviewer is very quiet and gives no feedback to your answers.","How would you handle a silent, non-reactive interviewer?","I would not let the silence unnerve me. I would answer each question thoroughly and confidently, make eye contact, and maintain a positive demeanor. I would not fill silence with nervous chatter. I would continue to provide strong examples and ask thoughtful questions. Some interviewers deliberately stay neutral to assess how candidates perform without validation.","Maintaining composure without external validation.","intermediate"),
  q("sq-bg2-47",ip,"panel_interview","A nurse manager and a clinical educator are both on the panel with different perspectives.","How would you tailor answers to a mixed panel?","I would balance clinical and leadership aspects in my answers—addressing the clinical educator's interest in my clinical skills and learning orientation while addressing the nurse manager's interest in reliability, teamwork, and unit fit. I would make eye contact with each panel member and direct answers to whoever asked. I would demonstrate that I value both clinical excellence and organizational commitment.","Audience-aware communication for diverse panels.","intermediate"),
  q("sq-bg2-48",ws,"medication_error","A patient is prescribed a look-alike, sound-alike medication that is easily confused with another drug.","How would you prevent LASA medication errors?","I would use tall-man lettering to differentiate medications, always verify using the generic name and indication, use barcode scanning, and confirm with the pharmacist if there is any doubt. I would educate the patient about their medication so they can serve as an additional safety check. I would report any confusing labels or names to the safety committee for systemic intervention.","LASA medication safety strategies.","intermediate"),
  q("sq-bg2-49",ws,"handoff_communication","You are handing off a patient who is actively deteriorating.","How would you conduct handoff during active patient deterioration?","I would provide a rapid, focused report at the bedside: current situation, what has been done, what is pending, and what to watch for. I would not leave until the receiving nurse confirms they understand the acuity. If the patient is actively crashing, I would stay and assist with stabilization before completing the formal handoff. Patient safety supersedes shift schedules.","Abbreviated critical handoff with continued support.","advanced"),
  q("sq-bg2-50",ct,"critical_thinking_drills","A patient has a BNP level of 1,200 pg/mL.","What does a markedly elevated BNP indicate?","BNP (B-type natriuretic peptide) above 400 pg/mL is strongly suggestive of heart failure. A level of 1,200 indicates significant cardiac wall stress and volume overload. I would assess for heart failure symptoms: dyspnea, orthopnea, edema, crackles, jugular venous distention. I would ensure the patient has daily weights, fluid restriction, low-sodium diet, and that diuretics are being administered as ordered.","BNP interpretation for heart failure assessment.","intermediate"),
  q("sq-bg2-51",ip,"clinical_judgment","A patient on continuous bladder irrigation develops dark red urine with clots.","How would you manage CBI with clot obstruction?","I would increase the irrigation rate to clear clots, ensure the catheter is draining freely, and manually irrigate with a catheter-tip syringe if clots are obstructing flow. I would monitor for bladder distension and patient discomfort. I would assess vital signs for hemorrhage. I would notify the urologist if the bleeding is heavy or the catheter becomes completely occluded despite irrigation.","CBI troubleshooting and hemorrhage monitoring.","intermediate"),
  q("sq-bg2-52",ws,"patient_safety","A patient with a latex allergy needs urinary catheterization.","How would you prepare for catheterization of a latex-allergic patient?","I would ensure all supplies are latex-free: silicone catheter, non-latex gloves, and hypoallergenic tape. I would verify the catheterization kit is a latex-free version. I would have epinephrine and diphenhydramine available in case of reaction. I would document the allergy prominently and inform all team members. I would verify the allergy type—IgE-mediated versus contact sensitivity—to gauge reaction severity risk.","Latex-safe procedure preparation.","intermediate"),
  q("sq-bg2-53",pd,"ethical_dilemmas","A patient's advance directive specifies no intubation, but the family is insisting on a ventilator.","How would you support adherence to an advance directive against family wishes?","I would review the advance directive with the family, involve the ethics committee and palliative care team, and clearly explain the legal weight of the patient's documented wishes. I would provide emotional support to the family while firmly advocating for the patient's autonomy. The advance directive represents the patient's voice when they cannot speak for themselves—it must be honored.","Legal and ethical advocacy for advance directive compliance.","advanced"),
  q("sq-bg2-54",cn,"career_advancement","You are interested in becoming an organ procurement coordinator.","How would you pursue organ procurement nursing?","I would gain ICU or critical care experience as a foundation. I would learn about brain death protocols, organ preservation, and the donation process. I would connect with the local organ procurement organization about volunteer and shadowing opportunities. I would pursue relevant certifications and attend transplant nursing conferences. This specialty combines clinical expertise with compassionate family support during the most difficult time.","Specialty career exploration in organ procurement.","intermediate"),
  q("sq-bg2-55",ct,"time_management","You need to manage a patient on multiple timed interventions with different frequencies.","How would you organize care with multiple timed interventions?","I would create a timeline for the shift showing all timed interventions: Q2H vital signs, Q4H neuro checks, Q1H position changes, Q6H medication, etc. I would look for overlapping times to cluster care. I would set alarms for critical timing and document each intervention as completed. A visual timeline prevents missed interventions and helps me plan my movements efficiently.","Visual timeline planning for multi-interval care.","intermediate"),
  q("sq-bg2-56",pd,"advocacy","A patient wants to try complementary medicine alongside their conventional treatment.","How would you support a patient interested in integrative medicine?","I would listen to what complementary approaches they are interested in and assess for safety: potential interactions with medications or treatments, evidence base, and the patient's understanding. I would facilitate a conversation with their physician about integrating complementary approaches safely. I would document the patient's interest and any approved integrative therapies.","Evidence-informed support for integrative medicine within safety parameters.","intermediate"),
  q("sq-bg2-57",ws,"interdisciplinary_communication","You need to coordinate care across three different specialist teams.","How would you coordinate multiple specialist teams?","I would maintain a current summary of each team's recommendations and identify conflicts. I would advocate for a unified care conference or ensure the primary team synthesizes specialist recommendations. I would serve as the communication hub, updating each team about relevant changes. I would document all communication and flag conflicting recommendations for resolution.","Nursing as the coordination hub for multi-specialty care.","advanced"),
  q("sq-bg2-58",ip,"behavioral","Tell me about a time you advocated for yourself professionally.","How do you practice self-advocacy?","When I was consistently assigned to precept students without additional support or reduced patient load, I scheduled a meeting with my manager. I presented data showing the impact on my workload and patient care. I proposed a solution: either reduce my patient load on precepting days or provide compensation for the additional responsibility. My manager appreciated the professional approach and implemented the reduced load option.","Data-driven professional self-advocacy.","intermediate"),
  q("sq-bg2-59",ct,"critical_thinking_drills","A patient's pH is 7.50 with a PaCO2 of 28 and HCO3 of 24.","What does this ABG indicate?","This ABG shows respiratory alkalosis—the patient is hyperventilating, blowing off too much CO2, resulting in an alkalotic pH. Common causes include anxiety, pain, fever, PE, or early sepsis. The normal HCO3 indicates no metabolic compensation, suggesting an acute process. I would assess the patient for underlying causes, calm them if anxiety-related, check for pain, and notify the provider for evaluation.","Respiratory alkalosis identification and cause investigation.","intermediate"),
  q("sq-bg2-60",ip,"clinical_judgment","A patient with a mechanical heart valve develops melena and has an INR of 5.5.","How would you manage bleeding in a mechanical valve patient?","This is complex because stopping anticoagulation risks valve thrombosis, but the bleeding must be controlled. I would notify the cardiologist and gastroenterologist simultaneously, hold warfarin, administer vitamin K per order (using a low dose to avoid over-correction), prepare for possible FFP or PCC, and anticipate emergent endoscopy. The goal is to correct the INR enough to stop bleeding while minimizing thromboembolic risk.","Balancing bleeding control with thrombosis prevention in mechanical valve patients.","advanced"),
  q("sq-bg2-61",ws,"delegation","You need to delegate post-mortem care to a CNA who has never done it.","How would you prepare a CNA for first-time post-mortem care?","I would acknowledge that this can be an emotional experience and ask if they are comfortable. I would walk them through the process: removing lines per policy, bathing and positioning the patient, applying clean linens, and preparing for family viewing. I would stay available for support and check in afterward. I would offer to perform the care together rather than delegating it entirely for a first experience.","Supportive guidance for emotionally challenging delegated tasks.","intermediate"),
  q("sq-bg2-62",cn,"performance_evaluation","Your evaluation is good but you feel underappreciated.","How would you address feeling undervalued despite positive evaluations?","I would reflect on what specifically makes me feel underappreciated: lack of verbal recognition, limited advancement opportunities, or compensation that does not reflect my contributions. I would have an honest conversation with my manager about my needs: 'I appreciate the positive evaluation. I would also benefit from more regular feedback and recognition. What opportunities are available for me to grow into a more impactful role?'","Identifying specific unmet recognition needs.","intermediate"),
  q("sq-bg2-63",ip,"scenario_responses","A patient asks you to pray with them.","How would you respond to a patient's request for prayer?","If I am comfortable and it aligns with the patient's needs, I would respectfully participate. If I am not comfortable, I would say, 'I appreciate your faith and want to support you. While prayer is not something I practice, I can sit with you quietly while you pray, or I can arrange for our chaplain to visit.' I would support their spiritual needs without imposing my own beliefs or comfort level.","Spiritual support within personal comfort boundaries.","beginner"),
  q("sq-bg2-64",pd,"professional_boundaries","A patient offers to connect you with a job opportunity through their company.","How would you handle a professional networking offer from a patient?","I would decline politely: 'I appreciate you thinking of me. While I need to maintain my professional boundaries during your care, I am grateful for the kind thought.' After the patient is discharged and the professional relationship has ended, some facilities may allow professional networking, but I would check my facility's policy first.","Boundary maintenance during active care relationship.","beginner"),
  q("sq-bg2-65",ct,"documentation_challenges","You need to document a complex wound with multiple stages and undermining.","How would you document a complex wound assessment?","I would use a standardized wound assessment tool and document: location, size (length x width x depth in cm), wound bed description (percentage of granulation, slough, eschar), edges, tunneling or undermining with clock-face direction and depth, surrounding skin, exudate type and amount, odor, and current treatment. I would take measurements consistently and compare to previous assessments to track healing.","Comprehensive standardized wound documentation.","intermediate"),
  q("sq-bg2-66",ws,"patient_safety","A patient's family is bringing in food that conflicts with their prescribed diet.","How would you address family bringing inappropriate foods?","I would educate the family about the prescribed diet and why it matters for recovery: 'I know you want to bring comfort food, and I appreciate that. However, the low-sodium diet is essential for managing their heart condition. Let me give you a list of approved foods so you can bring items that are both comforting and safe.' I would involve the dietitian for family education.","Family education about diet compliance with approved alternatives.","beginner"),
  q("sq-bg2-67",ip,"clinical_judgment","A patient develops rigidity, high fever, and altered mental status after starting haloperidol.","What syndrome do you suspect?","These symptoms suggest neuroleptic malignant syndrome—a rare but life-threatening reaction to antipsychotic medications. I would stop the haloperidol immediately, provide aggressive cooling measures, ensure IV access for aggressive fluid resuscitation, monitor creatine kinase for rhabdomyolysis, and notify the provider STAT. I would anticipate transfer to ICU and possible dantrolene administration.","NMS recognition with immediate antipsychotic cessation.","advanced"),
  q("sq-bg2-68",ct,"new_nurse_anxiety","You feel overwhelmed by the amount of continuing education required.","How would you manage continuing education requirements efficiently?","I would create a timeline for the year, spreading requirements evenly rather than cramming at the last minute. I would look for free CE opportunities through professional organizations and my employer. I would choose topics that align with my clinical interests and career goals. I would integrate learning into daily practice by turning clinical questions into CE search opportunities.","Strategic CE planning aligned with career interests.","beginner"),
  q("sq-bg2-69",pd,"patient_communication","A patient is scared about a new diagnosis and keeps asking the same questions repeatedly.","How would you handle repetitive questioning from an anxious patient?","I would recognize that repetitive questioning often stems from anxiety and the brain's difficulty processing information during stress. I would answer patiently each time, provide written materials to reference, and acknowledge their anxiety: 'I know this is a lot to take in. It is okay to ask as many times as you need. I will be here.' I would also assess whether the repetitive questioning indicates a cognitive issue.","Patient patience with anxiety recognition.","beginner"),
  q("sq-bg2-70",cn,"career_advancement","You want to get involved in nursing quality and patient safety.","How would you develop expertise in patient safety?","I would volunteer for the unit's safety committee, participate in root cause analysis and failure mode analysis, study human factors engineering, and pursue certification in patient safety (CPPS). I would read patient safety literature and attend safety conferences. Understanding safety science—just culture, Swiss cheese model, and high reliability principles—provides a framework for meaningful safety improvement work.","Patient safety science foundation with practical involvement.","intermediate"),
  q("sq-bg2-71",ip,"behavioral","Describe a situation where you demonstrated resilience.","How have you shown resilience in nursing?","During a particularly challenging clinical rotation where I cared for multiple critically ill patients in one week, including a patient death, I felt emotionally drained. Rather than withdrawing, I sought support from my clinical instructor, practiced self-care, and returned the next week more determined. I recognized that resilience is not about not feeling—it is about continuing to show up and provide compassionate care despite the emotional toll.","Authentic resilience with emotional honesty.","intermediate"),
  q("sq-bg2-72",ws,"difficult_coworkers","A nurse on your unit has a habit of leaving early and asking you to watch their patients.","How would you handle a colleague who consistently leaves early?","I would decline to assume their patients: 'I am not comfortable taking responsibility for your patients when you leave early. If you need to leave, please arrange coverage with the charge nurse.' I would document each occurrence and report the pattern to the charge nurse. Informal patient hand-offs without proper communication are unsafe.","Refusing unsafe informal patient transfers.","intermediate"),
  q("sq-bg2-73",ct,"critical_thinking_drills","A patient's ammonia level is 85 mcg/dL.","What does an elevated ammonia level indicate?","Elevated ammonia (normal <35 mcg/dL) indicates the liver is not adequately metabolizing ammonia, suggesting hepatic encephalopathy in liver disease patients or metabolic disorders. I would assess neurological status, initiate lactulose therapy if not already started, restrict protein intake per orders, monitor for asterixis, and notify the provider. I would grade the encephalopathy severity and monitor for progression.","Ammonia interpretation in liver disease context.","intermediate"),
  q("sq-bg2-74",pd,"advocacy","A patient on Medicaid is not receiving the same specialist referrals as privately insured patients.","How would you address insurance-based care disparities?","I would advocate for equitable care by ensuring the patient's clinical needs are the basis for referral decisions, not insurance status. I would document the clinical indication for the referral, work with social services to find specialists who accept Medicaid, and escalate concerns about inequitable care to the charge nurse and patient advocate. All patients deserve appropriate medical care regardless of insurance.","Insurance-blind advocacy for appropriate clinical care.","advanced"),
  q("sq-bg2-75",cn,"probation_period","You want to build a professional portfolio during your first year.","What should a new nurse's professional portfolio include?","A professional portfolio should include: resume, nursing license, certifications, education transcripts, professional development records, clinical competency checklists, positive patient feedback, quality improvement contributions, committee participation, performance evaluations, and professional goals. A well-maintained portfolio supports career advancement, certification applications, and future job searches.","Comprehensive professional portfolio development.","beginner"),
  q("sq-bg2-76",ip,"clinical_judgment","A patient on an insulin drip has a blood glucose of 250 that has not changed in 4 hours despite dose increases.","Why might insulin resistance occur and what would you do?","Insulin resistance can occur due to infection, stress, steroid use, obesity, or incorrect insulin concentration. I would verify the insulin drip concentration and tubing, ensure the pump is functioning correctly, check for infiltrated IV access, assess for underlying infection or stress, and notify the provider. I would also ensure the insulin is being administered through a dedicated line.","Troubleshooting insulin resistance with systematic assessment.","intermediate"),
  q("sq-bg2-77",ws,"handoff_communication","You are receiving a patient from the emergency department with minimal documentation.","How would you handle an ED admission with sparse documentation?","I would obtain a thorough verbal report from the ED nurse using SBAR. I would ask specific questions about the clinical presentation, treatments given, lab results, and the patient's response. I would perform my own comprehensive admission assessment and reconcile medications. I would document any information gaps and follow up on pending results. ED-to-floor transitions are high-risk for information loss.","Proactive information gathering during ED-to-floor transitions.","intermediate"),
  q("sq-bg2-78",ct,"time_management","You are behind on your assessment documentation and your manager emphasizes timely charting.","How would you catch up on delayed documentation?","I would focus on documenting the most clinically significant findings first—abnormal assessments, interventions, and provider notifications. I would use efficient charting techniques: templates, copy-forward for stable findings with verification, and system shortcuts. I would set a realistic catch-up timeline and communicate with my charge nurse if I need support. Going forward, I would identify what caused the delay and adjust my workflow.","Prioritized documentation catch-up with workflow analysis.","beginner"),
  q("sq-bg2-79",pd,"workplace_bullying","A colleague makes comments about your weight or fitness in front of patients.","How would you address body-shaming comments from a colleague?","I would address it firmly and privately: 'Comments about my body are not appropriate in the workplace and are especially harmful in front of patients. I need those comments to stop immediately.' If they continued, I would document each incident and report to HR as this constitutes workplace harassment. No one should have to tolerate body-shaming at work.","Zero-tolerance approach to body-based harassment.","intermediate"),
  q("sq-bg2-80",cn,"career_advancement","You are interested in hospice and palliative care nursing.","How would you transition into hospice nursing?","I would develop skills in pain management, symptom control, end-of-life communication, and family support through my current practice. I would shadow hospice nurses, pursue certification in hospice and palliative care (CHPN), and volunteer with hospice organizations. I would develop comfort with death and dying through deliberate clinical experiences and personal reflection. Hospice nursing requires both clinical skill and emotional maturity.","Hospice transition preparation combining clinical and emotional development.","intermediate"),
];
